1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	
5	type Item = { type: string };
6	type QuoteStep = { op: "quote"; items: Item[] };
7	type Step = QuoteStep;
8	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	};
17	
18	const COMPONENT_TYPES = new Set(["rune"]);
19	
20	const countByType = (items: Item[]): Map<string, number> => {
21	  const counts = new Map<string, number>();
22	  for (const item of items) {
23	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
24	  }
25	  return counts;
26	};
27	
28	const basePremiumOf = (items: Item[]): number => {
29	  const counts = countByType(items);
30	  let total = 0;
31	  for (const [type, count] of counts) {
32	    if (COMPONENT_TYPES.has(type) && count === 3) {
33	      total += BLOCK_OF_THREE_PREMIUM;
34	    } else {
35	      total += count * BASE_PREMIUMS[type];
36	    }
37	  }
38	  return total;
39	};
40	
41	const quoteForStep = ({ items }: QuoteStep) => {
42	  const basePremium = basePremiumOf(items);
43	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
44	  return { premium: basePremium + firstInsuranceSurcharge + PROCESSING_FEE };
45	};
46	
47	export const runScenario = (scenario: Scenario): unknown => {
48	  return { results: scenario.steps.map(quoteForStep) };
49	};
